### Solution Code
```rust
fn solve(s: String) -> String {
    let mut result = String::new();
    for c in s.chars() {
        match c {
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            }
            '#' => {
                let duplicate = result.clone();
                result.push_str(&duplicate);
            }
            '%' => {
                result = result.chars().rev().collect();
            }
            _ => {
                result.push(c);
            }
        }
    }
    result
}
```

